def get_html_template() -> str:
    local = Path(__file__).parent / "index.html"
    if local.exists(): return local.read_text(encoding="utf-8")
    return base64.b64decode(_HTML_B64).decode("utf-8")
MO_MAP={1:"Ene",2:"Feb",3:"Mar",4:"Abr",5:"May",6:"Jun",7:"Jul",8:"Ago",9:"Sep",10:"Oct",11:"Nov",12:"Dic"}
def clean(v)->str:
    if v is None: return ""
    s=str(v).strip(); return "" if s.lower() in ("nan","none","nat","") else s
def norm(s)->str:
    import unicodedata
    s=unicodedata.normalize("NFD",str(s))
    s="".join(c for c in s if unicodedata.category(c)!="Mn")
    return s.lower().replace(" ","").replace("_","")
def procesar_excel(archivo)->list:
    df=pd.read_excel(archivo,dtype=str); df.columns=[str(c).strip() for c in df.columns]
    col_fecha=None
    for c in df.columns:
        if any(p in norm(c) for p in ["fecha","date","fec","ingreso"]): col_fecha=c; break
    rows=[]
    for _,row in df.iterrows():
        obj={col:clean(row[col]) for col in df.columns}
        if col_fecha and obj.get(col_fecha):
            try:
                dt=pd.to_datetime(obj[col_fecha],dayfirst=True,errors="coerce")
                if pd.notna(dt):
                    obj[col_fecha]=dt.strftime("%Y-%m-%d")
                    obj["__PERIODO__"]=f"{MO_MAP[dt.month]}-{str(dt.year)[2:]}"
                    obj["__ANIO__"]=str(dt.year)
                else: obj["__PERIODO__"]=obj["__ANIO__"]=""
            except: obj["__PERIODO__"]=obj["__ANIO__"]=""
        else: obj["__PERIODO__"]=obj["__ANIO__"]=""
        rows.append(obj)
    return rows
def generar_html(rows,password,filename)->str:
    html=get_html_template()
    json_data=json.dumps(rows,ensure_ascii=True,separators=(",",":"))
    html=html.replace("let RAW = [], COLS = [], CHARTS = {}, PAGE = 1;",f"let RAW = {json_data}, COLS = [], CHARTS = {{}}, PAGE = 1;")
    html=html.replace("const DASHBOARD_PASSWORD = 'pap2025';",f"const DASHBOARD_PASSWORD = {json.dumps(password)};")
    html=html.replace("setTimeout(() => { overlay.style.display = 'none'; }, 460);","setTimeout(() => { overlay.style.display = 'none'; initDashboard(); }, 460);")
    return html
st.set_page_config(page_title="Dashboard PAP & Biopsias - CPP",page_icon="\U0001f9ec",layout="centered")
st.title("Generador Dashboard PAP & Biopsias")
st.markdown("Centro Privado de Patolog\u00eda - Subi tu Excel y descarga el dashboard listo para distribuir.")
with st.form("config"):
    archivo=st.file_uploader("Archivo Excel (.xlsx / .xls)",type=["xlsx","xls"])
    password=st.text_input("Contrasena del dashboard",value="pap2025",type="password")
    submitted=st.form_submit_button("Generar HTML",type="primary")
if submitted:
    if not archivo: st.warning("Selecciona un archivo Excel."); st.stop()
    if not password: st.warning("La contrasena no puede estar vacia."); st.stop()
    with st.spinner("Procesando..."):
        try:
            rows=procesar_excel(archivo); html_out=generar_html(rows,password,archivo.name)
            st.success(f"Dashboard generado con {len(rows):,} registros.")
            st.download_button("Descargar dashboard.html",html_out.encode("utf-8"),"dashboard.html","text/html",use_container_width=True)
            with st.expander("Vista previa (primeras 5 filas)"): st.json(rows[:5])
        except Exception as e: st.error(f"Error: {e}"); st.exception(e)
st.divider(); st.caption("Centro Privado de Patolog\u00eda \u00b7 Dashboard de Protocolos")
